	fmt.Fprintf(w, "logged %s on %s:%d\n", res.Type, res.Parent.Type, res.Parent.ID)
	if res.DeletedID != "" {
		fmt.Fprintf(w, "deleted original activity %s\n", res.DeletedID)
	}
	return nil
